DROP VIEW IF EXISTS VEntregas;
CREATE VIEW VEntregas (Sucursal, Pedido, FPedido, FEntrega, Banda, Cliente) 
AS 
	SELECT s.nombre, p.idPedido, DATE(p.fecha), DATE(e.fecha), bh.nombre, CONCAT(c.apellidos, ', ',c.nombres, ' (', c.dni, ')')
    FROM Sucursales s
    INNER JOIN Entregas e ON s.idSucursal = e.idSucursal
    INNER JOIN Pedidos p ON e.idPedido = p.idPedido
    INNER JOIN BandasHorarias bh ON e.idBandaHoraria = bh.idBandaHoraria
    INNER JOIN Clientes C ON p.idCliente = c.idCliente;
    
    
