DROP PROCEDURE IF EXISTS NuevoProducto;
DELIMITER //
CREATE PROCEDURE NuevoProducto(pNombre VARCHAR(150), pPrecio FLOAT, OUT mensaje VARCHAR(100))
SALIR: BEGIN  
	IF (pNombre IS NULL OR pNombre = '') OR (pPrecio <= 0 OR pPrecio IS NULL) THEN
		SET mensaje = 'Error ningun campo puede ser nulo';
        LEAVE SALIR;
	END IF;
    
	INSERT INTO Productos VALUES 
    (0, pNombre, pPrecio);
	SET mensaje = 'Producto creado con éxito';
END //
DELIMITER ;


DROP PROCEDURE IF EXISTS BuscarPedidos;
DELIMITER //
CREATE PROCEDURE BuscarPedidos(pPedido INT, OUT mensaje VARCHAR(100))
SALIR: BEGIN  
	IF (pPedido <= 0 OR pPedido IS NULL) THEN
		SET mensaje = 'Error ID invalido';
        LEAVE SALIR;
	END IF;
    
	(SELECT pr.idProducto, pr.nombre, pr.precio AS 'precio lista', pdp.cantidad, pdp.precio AS 'precio venta', (pdp.cantidad * pdp.precio) AS 'total'
    FROM Productos pr
    INNER JOIN ProductoDelPedido pdp ON pr.idProducto = pdp.idProducto
    INNER JOIN Pedidos pe ON pdp.idPedido = pe.idPedido
    WHERE pe.idPedido = pPedido
    ORDER BY 2 ASC)
    
    UNION
    
    (SELECT 'Fecha:', DATE(p.fecha), 'Cliente:', CONCAT(c.apellidos, ', ',c.nombres), 'Total:', SUM(pdp.Precio * pdp.cantidad)
    FROM Pedidos p
    INNER JOIN Clientes c ON p.idCliente = c.idCliente
    INNER JOIN ProductoDelPedido pdp ON p.idPedido = pdp.idPedido
    WHERE p.idPedido = pPedido
    GROUP BY pdp.idPedido)
    ;
    
	SET mensaje = 'Producto creado con éxito';
END //
DELIMITER ;


