DROP TRIGGER IF EXISTS BorradoProducto;
DELIMITER //
CREATE TRIGGER BorradoProducto 
BEFORE DELETE ON Productos FOR EACH ROW
BEGIN
    
    IF (SELECT MAX(precio) FROM ProductoDelPedido WHERE idProducto = OLD.idProducto) IS NOT NULL THEN
		SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'No se puede borrar producto'; 
    END IF;
    
END //
DELIMITER ;
